import json

with open(locals()['var_function-call-12318605142908816769'], 'r') as f:
    articles = json.load(f)

keywords = ["renewal", "expiration", "expired", "entitlement", "active contract", "support policy"]
matches = []

for art in articles:
    text = (art.get('title', '') + ' ' + art.get('faq_answer__c', '') + ' ' + art.get('summary', '')).lower()
    score = 0
    for kw in keywords:
        if kw in text:
            score += 1
    if score > 0:
        matches.append((score, art))

matches.sort(key=lambda x: x[0], reverse=True)

result = []
for score, art in matches[:10]:
    result.append({
        "id": art['id'],
        "title": art['title'],
        "summary": art['summary']
    })

print("__RESULT__:")
print(json.dumps(result, indent=2))

